import React, { useEffect, useState } from 'react';
import { getTasks, getResponsesForTask, getRatingsForResponse, createRating } from '../services/api';

interface Task {
  id: number;
  prompt: string;
  status: string;
}

interface Response {
  id: number;
  task_id: number;
  ai_model: string;
  response_text: string;
}

interface Rating {
  id: number;
  response_id: number;
  annotator_id: number;
  score: number;
  feedback: string;
}

const RatingsPage: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [selectedTask, setSelectedTask] = useState<number | null>(null);
  const [responses, setResponses] = useState<Response[]>([]);
  const [ratings, setRatings] = useState<{ [key: number]: Rating[] }>({});
  const [scores, setScores] = useState<{ [key: number]: number }>({});
  const [feedbacks, setFeedbacks] = useState<{ [key: number]: string }>({});
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const data = await getTasks();
      setTasks(data);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const handleSelectTask = async (taskId: number) => {
    setSelectedTask(taskId);
    setError('');
    setSuccess('');
    try {
      const data = await getResponsesForTask(taskId);
      setResponses(data);
      // fetch ratings for each response
      for (const response of data) {
        const ratingData = await getRatingsForResponse(response.id);
        setRatings(prev => ({ ...prev, [response.id]: ratingData }));
      }
    } catch (err) {
      setError('Failed to load responses');
    }
  };

  const handleSubmitRating = async (responseId: number) => {
    const score = scores[responseId];
    const feedback = feedbacks[responseId] || '';

    if (!score) {
      setError('Please select a score');
      return;
    }

    try {
      await createRating({
        response_id: responseId,
        annotator_id: 2,
        score,
        feedback
      });
      setSuccess('Rating submitted successfully');
      setError('');
      // refresh ratings
      const ratingData = await getRatingsForResponse(responseId);
      setRatings(prev => ({ ...prev, [responseId]: ratingData }));
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to submit rating');
    }
  };

  return (
    <div style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Rate Responses</h1>

      {/* Task selector */}
      <div style={{ marginBottom: '2rem' }}>
        <h2 style={{ fontSize: '1.1rem', marginBottom: '1rem' }}>Select a Task</h2>
        {tasks.map(task => (
          <div
            key={task.id}
            onClick={() => handleSelectTask(task.id)}
            style={{
              padding: '1rem',
              border: selectedTask === task.id ? '2px solid #2563eb' : '1px solid #eee',
              borderRadius: '8px',
              marginBottom: '0.75rem',
              cursor: 'pointer',
              background: selectedTask === task.id ? '#eff6ff' : 'white',
            }}
          >
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ fontWeight: 600 }}>Task #{task.id}</span>
              <span style={{
                background: task.status === 'completed' ? '#dcfce7' : '#fef9c3',
                color: task.status === 'completed' ? '#166534' : '#854d0e',
                padding: '0.2rem 0.6rem',
                borderRadius: '999px',
                fontSize: '0.8rem',
              }}>
                {task.status}
              </span>
            </div>
            <p style={{ color: '#555', marginTop: '0.4rem' }}>{task.prompt}</p>
          </div>
        ))}
      </div>

      {/* Responses and rating forms */}
      {selectedTask && responses.length === 0 && (
        <p style={{ color: '#888' }}>No responses for this task yet.</p>
      )}

      {responses.map(response => (
        <div key={response.id} style={{
          background: 'white',
          border: '1px solid #eee',
          borderRadius: '8px',
          padding: '1.5rem',
          marginBottom: '1.5rem',
          boxShadow: '0 1px 3px rgba(0,0,0,0.05)'
        }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.75rem' }}>
            <span style={{ fontWeight: 600, color: '#2563eb' }}>{response.ai_model}</span>
            <span style={{ color: '#999', fontSize: '0.8rem' }}>Response #{response.id}</span>
          </div>
          <p style={{ color: '#444', marginBottom: '1.25rem', lineHeight: '1.6' }}>
            {response.response_text}
          </p>

          {/* Existing ratings */}
          {ratings[response.id]?.length > 0 && (
            <div style={{ marginBottom: '1rem', padding: '0.75rem', background: '#f9f9f9', borderRadius: '6px' }}>
              <p style={{ fontWeight: 600, marginBottom: '0.5rem', fontSize: '0.9rem' }}>Existing Ratings:</p>
              {ratings[response.id].map(rating => (
                <div key={rating.id} style={{ fontSize: '0.85rem', color: '#555', marginBottom: '0.3rem' }}>
                  Score: {rating.score}/5 — {rating.feedback}
                </div>
              ))}
            </div>
          )}

          {/* Rating form */}
          <div>
            <p style={{ fontWeight: 500, marginBottom: '0.5rem', fontSize: '0.9rem' }}>Your Rating:</p>
            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem' }}>
              {[1, 2, 3, 4, 5].map(num => (
                <button
                  key={num}
                  onClick={() => setScores(prev => ({ ...prev, [response.id]: num }))}
                  style={{
                    width: '40px',
                    height: '40px',
                    borderRadius: '6px',
                    border: scores[response.id] === num ? '2px solid #2563eb' : '1px solid #ddd',
                    background: scores[response.id] === num ? '#2563eb' : 'white',
                    color: scores[response.id] === num ? 'white' : '#444',
                    cursor: 'pointer',
                    fontWeight: 600,
                  }}
                >
                  {num}
                </button>
              ))}
            </div>
            <textarea
              placeholder="Optional feedback..."
              value={feedbacks[response.id] || ''}
              onChange={(e) => setFeedbacks(prev => ({ ...prev, [response.id]: e.target.value }))}
              style={{
                width: '100%',
                minHeight: '70px',
                padding: '0.6rem',
                borderRadius: '6px',
                border: '1px solid #ddd',
                fontSize: '0.9rem',
                marginBottom: '0.75rem',
                boxSizing: 'border-box',
                resize: 'vertical'
              }}
            />
            <button
              onClick={() => handleSubmitRating(response.id)}
              style={{
                background: '#2563eb',
                color: 'white',
                border: 'none',
                padding: '0.5rem 1.2rem',
                borderRadius: '6px',
                cursor: 'pointer',
                fontSize: '0.9rem'
              }}
            >
              Submit Rating
            </button>
          </div>
        </div>
      ))}

      {error && <p style={{ color: 'red', marginTop: '1rem' }}>{error}</p>}
      {success && <p style={{ color: 'green', marginTop: '1rem' }}>{success}</p>}
    </div>
  );
};

export default RatingsPage;
